  private final CdsIndex underlyingIndex;
  /**
   * The attachment point.
   * <p>
   * This is the lower subordination boundary as a fraction (0.0 to 1.0).
   * Losses below this point are absorbed by the most senior tranches.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double attachmentPoint;
  /**
   * The detachment point.
   * <p>
   * This is the upper subordination boundary as a fraction (0.0 to 1.0).
   * Losses above this point are not absorbed by this tranche.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double detachmentPoint;

